        let c = view_class[(id + 4 - this.viewpoint) % 4];
        let open = this._model.player_id[l] == this.viewpoint
                    || this.open_shoupai;
        this._view.shoupai[l] = new Shoupai($(`.shoupai.${c}`, this._root),
                                        this._model.shoupai[l]).redraw(open);
